const seoOutput = $input.first().json.output;
const scriptData = $('5. Set — Save Script and Config').item.json;

if (!seoOutput) {
  throw new Error('GPT did not return SEO data. Check your OpenAI credential.');
}

const title = seoOutput.title || 'Untitled';
const altTitles = (seoOutput.alternativeTitles || []).map((t, i) => (i + 1) + '. ' + t).join('\n');
const description = seoOutput.description || 'No description generated.';
const tags = (seoOutput.tags || []).join(', ');
const chapters = (seoOutput.chapters || []).map(c => c.timestamp + ' ' + c.title).join('\n');

const emailBody =
  'Hello ' + scriptData.senderName + ',\n\n' +
  'Your YouTube content package is ready.\n\n' +
  'Topic: ' + scriptData.videoTopic + '\n' +
  'Audience: ' + scriptData.targetAudience + '\n' +
  'Length: ' + scriptData.videoLength + '\n' +
  'Date: ' + scriptData.today + '\n\n' +
  '============================================================\n' +
  'TITLES\n' +
  '============================================================\n\n' +
  'Main title:\n' + title + '\n\n' +
  'Alternative titles to test:\n' + altTitles + '\n\n' +
  '============================================================\n' +
  'TAGS\n' +
  '============================================================\n\n' +
  tags + '\n\n' +
  '============================================================\n' +
  'CHAPTERS\n' +
  '============================================================\n\n' +
  chapters + '\n\n' +
  '============================================================\n' +
  'DESCRIPTION\n' +
  '============================================================\n\n' +
  description + '\n\n' +
  '============================================================\n' +
  'VIDEO SCRIPT\n' +
  '============================================================\n\n' +
  scriptData.videoScript + '\n\n' +
  'Best regards,\n' + scriptData.senderName;

return [{
  json: {
    emailSubject: 'YouTube Content Package — ' + title + ' — ' + scriptData.today,
    emailBody,
    recipientEmail: scriptData.recipientEmail
  }
}];
